{"content": """"
Hermes Context MCP Server
Gives Joinly access to:
- Client data (Nexa, etc.)
- Project documentation
- Skill library
- Business information
"""
import json, os, sys
from pathlib import Path

CLIENTS_DIR = Path("/root/ai-whisperers-base")
MEMORY_FILE = Path("/root/.hermes/memory.json")

def get_clients() -> list:
    """Get all clients from the monorepo."""
    clients = []
    # Scan packages for client data
    for pkg in (CLIENTS_DIR / "packages").iterdir():
        name = pkg.name.replace("client-", "").replace("-kit", "")
        clients.append({
            "name": name,
            "path": str(pkg),
            "package": pkg.name,
        })
    return clients

def get_client_details(name: str) -> dict:
    """Get detailed info about a specific client."""
    details = {}
    # Search for JSON content files
    for f in CLIENTS_DIR.rglob("**/*"):
        if f.is_file() and f.suffix in (".json", ".md", ".ts", ".tsx"):
            rel = f.relative_to(CLIENTS_DIR)
            if name.lower() in str(rel).lower():
                parts = list(rel.parts)
                details.setdefault("files", []).append(str(rel))
    return details

def get_recent_work() -> list:
    """Get recent project work context."""
    work = []
    # Check the Nexa site
    nexa_dir = Path("/tmp/nexa-paraguay")
    if nexa_dir.exists():
        work.append({"project": "Nexa Paraguay", "path": str(nexa_dir)})
    return work

# === MCP Handler ===
request = json.loads(sys.stdin.read())
method = request.get("method")
params = request.get("params", {})
req_id = request.get("id", 1)

result = {}

if method == "tools/list":
    result = {
        "tools": [
            {
                "name": "get_clients",
                "description": "Get list of all Ai-Whisperers clients and their info",
                "inputSchema": {"type": "object", "properties": {}}
            },
            {
                "name": "get_client",
                "description": "Get detailed info about a specific client by name",
                "inputSchema": {
                    "type": "object",
                    "properties": {
                        "name": {"type": "string", "description": "Client name (e.g. nexa, 3md)"}
                    },
                    "required": ["name"]
                }
            },
            {
                "name": "get_skills",
                "description": "Get list of available skills and procedures",
                "inputSchema": {"type": "object", "properties": {}}
            },
            {
                "name": "search_work",
                "description": "Search project documentation and work history",
                "inputSchema": {
                    "type": "object",
                    "properties": {
                        "query": {"type": "string", "description": "Search term"}
                    },
                    "required": ["query"]
                }
            },
            {
                "name": "get_business_info",
                "description": "Get general business info about Ai-Whisperers",
                "inputSchema": {"type": "object", "properties": {}}
            },
        ]
    }

elif method == "tools/call":
    tool = params.get("name")
    args = params.get("arguments", {})

    if tool == "get_clients":
        result = {"content": [{"type": "text", "text": json.dumps(get_clients(), indent=2)}]}

    elif tool == "get_client":
        name = args.get("name", "")
        result = {"content": [{"type": "text", "text": json.dumps(get_client_details(name), indent=2)}]}

    elif tool == "get_skills":
        skills_dir = Path("/root/.hermes/skills")
        skills = []
        if skills_dir.exists():
            for s in skills_dir.iterdir():
                if s.is_dir():
                    skills.append({"name": s.name})
        result = {"content": [{"type": "text", "text": json.dumps(skills, indent=2)}]}

    elif tool == "search_work":
        query = args.get("query", "")
        results = []
        # Search through recent project data
        work = get_recent_work()
        for w in work:
            results.append(w)
        result = {"content": [{"type": "text", "text": json.dumps(results, indent=2)}]}

    elif tool == "get_business_info":
        info = {
            "name": "Ai-Whisperers",
            "services": ["Web development", "AI agents", "SEO", "Hosting"],
            "tech_stack": ["Next.js", "React", "TypeScript", "Tailwind", "Docker Swarm", "Hermes Agent"],
            "pricing": {
                "basico": "187,000 Gs/mo",
                "profesional": "381,000 Gs/mo",
                "empresa": "639,000 Gs/mo",
                "setup": "450,000 Gs one-time"
            }
        }
        result = {"content": [{"type": "text", "text": json.dumps(info, indent=2)}]}

# Output JSON-RPC response
response = {"jsonrpc": "2.0", "id": req_id, "result": result}
print(json.dumps(response))
